import{c as e,Q as o,j as a,m as r}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"MemTool: Optimizing Short-Term Memory Management for Dynamic Tool Calling in LLM Agent Multi-Turn Conversations","description":"","frontmatter":{"title":"MemTool: Optimizing Short-Term Memory Management for Dynamic Tool Calling in LLM Agent Multi-Turn Conversations","arxiv_id":2507.21428,"authors":"Elias Lumer, Anmol Gulati, Vamse Kumar Subbiah, Pradeep Honaganahalli Basavaraju, James A. Burke","fetched":"2026-05-26T00:00:00.000Z","published":"2025-07-29T00:00:00.000Z","source":"https://arxiv.org/abs/2507.21428","source_tier":"P"},"headers":[],"relativePath":"research/papers/2025-07-29-memtool-short-term-memory-dynamic-tool-calling-2507.21428.md","filePath":"research/papers/2025-07-29-memtool-short-term-memory-dynamic-tool-calling-2507.21428.md","lastUpdated":1779901665000}'),n={name:"research/papers/2025-07-29-memtool-short-term-memory-dynamic-tool-calling-2507.21428.md"};function i(l,t,s,d,m,c){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="memtool-optimizing-short-term-memory-management-for-dynamic-tool-calling-in-llm-agent-multi-turn-conversations" tabindex="-1">MemTool: Optimizing Short-Term Memory Management for Dynamic Tool Calling in LLM Agent Multi-Turn Conversations <a class="header-anchor" href="#memtool-optimizing-short-term-memory-management-for-dynamic-tool-calling-in-llm-agent-multi-turn-conversations" aria-label="Permalink to &quot;MemTool: Optimizing Short-Term Memory Management for Dynamic Tool Calling in LLM Agent Multi-Turn Conversations&quot;">​</a></h1><p><strong>Authors</strong>: Elias Lumer, Anmol Gulati, Vamse Kumar Subbiah, Pradeep Honaganahalli Basavaraju, James A. Burke (Commercial Technology and Innovation Office, PricewaterhouseCoopers, U.S.A.) <strong>Published</strong>: July 2025 <strong>Source</strong>: <a href="https://arxiv.org/abs/2507.21428" target="_blank" rel="noreferrer">https://arxiv.org/abs/2507.21428</a><strong>arXiv ID</strong>: 2507.21428 <strong>Categories</strong>: cs.CL (Computation and Language)</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>Large Language Model (LLM) agents have shown significant autonomous capabilities in dynamically searching and incorporating relevant tools or Model Context Protocol (MCP) servers for individual queries. However, fixed context windows limit effectiveness in multi-turn interactions requiring repeated, independent tool usage. We introduce MemTool, a short-term memory framework enabling LLM agents to dynamically manage tools or MCP server contexts across multi-turn conversations. MemTool offers three agentic architectures: 1) Autonomous Agent Mode, granting full tool management autonomy, 2) Workflow Mode, providing deterministic control without autonomy, and 3) Hybrid Mode, combining autonomous and deterministic control. Evaluating each MemTool mode across 13+ LLMs on the ScaleMCP benchmark, we conducted experiments over 100 consecutive user interactions, measuring tool removal ratios (short-term memory efficiency) and task completion accuracy. In Autonomous Agent Mode, reasoning LLMs achieve high tool-removal efficiency (90–94% over a 3-window average), while medium-sized models exhibit significantly lower efficiency (0–60%). Workflow and Hybrid modes consistently manage tool removal effectively, whereas Autonomous and Hybrid modes excel at task completion. We present trade-offs and recommendations for each MemTool mode based on task accuracy, agency, and model capabilities.</p><hr><h2 id="core-thesis" tabindex="-1">Core Thesis <a class="header-anchor" href="#core-thesis" aria-label="Permalink to &quot;Core Thesis&quot;">​</a></h2><p>MemTool addresses the gap in short-term tool memory management for LLM agents in multi-turn conversations: while existing work focuses on compressing conversational context via summarization/truncation, no prior work evaluated how agents manage dynamic tool context (adding and removing tools) across 100+ sequential turns. Three architectures with varying autonomy levels are proposed and benchmarked across 13+ LLMs, revealing that reasoning models handle autonomous tool removal well (90–94%), while smaller models require deterministic workflow scaffolding to achieve comparable removal efficiency.</p><hr><h2 id="_1-introduction" tabindex="-1">1. Introduction <a class="header-anchor" href="#_1-introduction" aria-label="Permalink to &quot;1. Introduction&quot;">​</a></h2><p>The LLM is the CPU, and its context window is the RAM (adapted from Andrej Karpathy, &quot;Software in the Era of AI,&quot; Y Combinator AI Startup School, June 2025).</p><p>Recent breakthroughs in LLM agents enable scalable agentic systems that autonomously search, discover, equip, and use a dynamic repository of tools or MCP servers. Dynamic tool calling allows agents to interact with external APIs without being constrained to a fixed toolset at initialization — analogous to a human navigating a mobile app store.</p><p>As LLM agents become embedded in session-based applications (chat, voice, video), managing limited context windows becomes necessary for multi-turn conversations. <strong>Context engineering</strong> and <strong>memory management</strong> systems allow multi-turn interactions to persist within a session (short-term memory) and across sessions (long-term memory).</p><p><strong>The gap</strong>: Current literature on short-term memory focuses on compressing conversation history via summarization or truncation of messages, but does not address the dynamic retrieval and management of tools within an agent&#39;s context window. Previous work shows agents can handle thousands of tools via RAG without accuracy drops — but none addresses the <em>removal and management</em> of tools across 100+ multi-turn sessions while using native function calling.</p><p>MemTool fills this gap with three modes for managing an LLM agent&#39;s context window of tools across multi-turn conversations.</p><hr><h2 id="_2-background" tabindex="-1">2. Background <a class="header-anchor" href="#_2-background" aria-label="Permalink to &quot;2. Background&quot;">​</a></h2><h3 id="_2-1-memory-for-llm-agents" tabindex="-1">2.1 Memory for LLM Agents <a class="header-anchor" href="#_2-1-memory-for-llm-agents" aria-label="Permalink to &quot;2.1 Memory for LLM Agents&quot;">​</a></h3><p>Existing literature divides memory for AI systems into:</p><ul><li><strong>Short-term memory</strong>: memories within the session; includes sensory memory (multi-modal inputs, tool calls) and working memory (system/assistant/human messages, chain of thoughts). Context engineering strategies involve summarization or truncation of previous messages.</li><li><strong>Long-term memory</strong>: persists across sessions. Includes explicit memory (episodic + semantic) and implicit memory (learned skills). Frameworks: Mem0, Zep, Letta.</li></ul><p>Summarizing long multi-turn dialogues is prone to over-summarization or information loss. MemTool is the first study to address and evaluate short-term memory for dynamic tool-use across multi-turn conversations.</p><h3 id="_2-2-tool-selection-and-retrieval-for-llm-agents" tabindex="-1">2.2 Tool Selection and Retrieval for LLM Agents <a class="header-anchor" href="#_2-2-tool-selection-and-retrieval-for-llm-agents" aria-label="Permalink to &quot;2.2 Tool Selection and Retrieval for LLM Agents&quot;">​</a></h3><p>Leading model providers impose limits of 128–512 tools per LLM API request. Prior work circumvents this with RAG strategies: storing large toolsets externally in vector databases or knowledge graphs, dynamically selecting only necessary tools at runtime.</p><p>Agentic RAG frameworks give LLM agents specialized tool-discovery tools that autonomously identify and invoke appropriate tools. Recent work (ScaleMCP) enables agents to dynamically query a repository of 5,000+ MCP servers. However, none address the removal and management of dynamic tools for 100+ multi-turn sessions.</p><h3 id="_2-3-tool-calling-llm-invocation" tabindex="-1">2.3 Tool Calling / LLM Invocation <a class="header-anchor" href="#_2-3-tool-calling-llm-invocation" aria-label="Permalink to &quot;2.3 Tool Calling / LLM Invocation&quot;">​</a></h3><p>MemTool deliberately adopts plug-and-play methodology compatible with out-of-the-box models and standard embedding solutions from OpenAI, Google, Anthropic, and Meta — no fine-tuning required. The framework equips the LLM with explicit operations for adding and removing tools from its active context.</p><hr><h2 id="_3-method-memtool" tabindex="-1">3. Method: MemTool <a class="header-anchor" href="#_3-method-memtool" aria-label="Permalink to &quot;3. Method: MemTool&quot;">​</a></h2><p>MemTool enables an LLM agent to manage its own context window of dynamic tools across multi-turn sessions. The broader implication: LLM agents can operate in production environments with a non-fixed set of tools, searching, equipping, and removing tools or MCP servers, similarly to a human navigating a mobile app store.</p><h3 id="_3-1-1-autonomous-agent-mode" tabindex="-1">3.1.1 Autonomous Agent Mode <a class="header-anchor" href="#_3-1-1-autonomous-agent-mode" aria-label="Permalink to &quot;3.1.1 Autonomous Agent Mode&quot;">​</a></h3><p>Grants full autonomy to the LLM agent to manage its context window while simultaneously answering the user task, across multi-turn conversations. Two additional tools are equipped to the agent:</p><ol><li><strong>Search_Tools(keywords: List[str])</strong>: adds tools from vector store to context (adapted from ScaleMCP)</li><li><strong>Remove_Tools(tool_names: List[str])</strong>: removes listed tools from the API call&#39;s tools parameter</li></ol><p><strong>Algorithm (summarized):</strong></p><ol><li>Prune previous messages (truncation or summarization) if token overflow</li><li>Add Search_Tools and Remove_Tools to the prior tool set</li><li>Enter a while loop: LLM calls tools as needed (searching, removing, executing)</li><li>If tool count exceeds limit L=128, raise an error prompting tool removal</li><li>Return final answer</li></ol><p><strong>Key implementation note</strong>: A dynamic variable for current tool count is passed in the system prompt on every query — this was critical for good removal behavior (without it, models failed to remove tools).</p><p><strong>Recommendations:</strong></p><ul><li>Use reasoning models (GPT-o3, Gemini 2.5 Pro/Flash, Claude Opus 4) for high removal efficiency</li><li>Include current tool count as a dynamic variable in the system message</li><li>Upper limit tool errors (e.g., 128) &quot;encourage&quot; LLMs to remove tools</li><li>Prompting with detailed guidelines on when to remove/add tools improves performance</li></ul><h3 id="_3-1-2-workflow-mode" tabindex="-1">3.1.2 Workflow Mode <a class="header-anchor" href="#_3-1-2-workflow-mode" aria-label="Permalink to &quot;3.1.2 Workflow Mode&quot;">​</a></h3><p>Limits LLM autonomy by abstracting tool management to a fixed deterministic workflow after every user query. Two fresh LLM calls occur in sequence:</p><ol><li>A <strong>prune LLM call</strong> removes irrelevant tools (no longer relevant to current query)</li><li>A <strong>search LLM call</strong> identifies keywords and retrieves new tools via vector search</li></ol><p>Only after this prune-then-search pipeline is the main LLM agent initialized with the updated tool set (without Remove_Tools, only with Search_Tools for any additional retrieval).</p><p><strong>Recommendations:</strong></p><ul><li>Recommended first choice for simplicity and reliability</li><li>Once LLM agent is initialized, no mechanism to revert to searching new tools</li><li>Self-correcting patterns become overly complex; Workflow intentionally avoids them</li></ul><h3 id="_3-1-3-hybrid-mode" tabindex="-1">3.1.3 Hybrid Mode <a class="header-anchor" href="#_3-1-3-hybrid-mode" aria-label="Permalink to &quot;3.1.3 Hybrid Mode&quot;">​</a></h3><p>Combines both approaches: the deterministic prune step (a fresh LLM call removes irrelevant tools) followed by full agent autonomy for searching and adding tools. Motivated by the observation that LLMs struggle with removal but perform well at searching/adding.</p><p><strong>Algorithm (summarized):</strong></p><ol><li>Prune LLM call removes irrelevant tools deterministically</li><li>LLM agent enters while loop with Search_Tools (no Remove_Tools) — free to search and add</li><li>If tool count exceeds L, a prune LLM call is triggered again before continuing</li></ol><p><strong>Recommendations:</strong></p><ul><li>Search_Tools enables re-querying if retrieved tools are insufficient</li><li>Agent is abstracted from tool removal, preventing removal errors</li><li>As models improve, Hybrid can transition to full Autonomous Agent Mode</li></ul><h3 id="_3-2-dataset" tabindex="-1">3.2 Dataset <a class="header-anchor" href="#_3-2-dataset" aria-label="Permalink to &quot;3.2 Dataset&quot;">​</a></h3><p>5,000 tools/MCP servers from the ScaleMCP benchmark. 100 instances sampled (stratified by number of tool calls per turn; average 5.0 tool calls per turn) for a 100 multi-turn tool-use dialogue.</p><hr><h2 id="_4-evaluations" tabindex="-1">4. Evaluations <a class="header-anchor" href="#_4-evaluations" aria-label="Permalink to &quot;4. Evaluations&quot;">​</a></h2><h3 id="_4-1-experiment-settings" tabindex="-1">4.1 Experiment Settings <a class="header-anchor" href="#_4-1-experiment-settings" aria-label="Permalink to &quot;4.1 Experiment Settings&quot;">​</a></h3><ul><li><strong>13 LLM models</strong> evaluated (closed and open source)</li><li><strong>Embedding model</strong>: Azure OpenAI text-embedding-ada-002</li><li><strong>Tool limit</strong>: 128 tools (standardized across all models; some models support 256–512)</li><li><strong>100 sequential user queries</strong> per experiment; each query may be related or unrelated to the prior</li><li><strong>Judge model</strong>: OpenAI GPT-4o mini (for Task Completion alignment scoring)</li></ul><p><strong>Metrics:</strong></p><ul><li><strong>Removal Ratio</strong>: proportion of tools successfully removed after being added (cumulative)</li><li><strong>AvgRemovalRatio_3T</strong>: rolling 3-turn window average removal ratio (primary efficiency metric)</li><li><strong>AvgResidual_3T</strong>: average number of tools remaining after a 3-turn grace window (tool accumulation)</li><li><strong>Task Completion</strong>: LLM-as-judge alignment between agent&#39;s final response and expected answer</li><li><strong>Tool Correctness</strong>: proportion of tool calls matching expected tool calls</li></ul><h3 id="_4-2-autonomous-agent-mode-results" tabindex="-1">4.2 Autonomous Agent Mode Results <a class="header-anchor" href="#_4-2-autonomous-agent-mode-results" aria-label="Permalink to &quot;4.2 Autonomous Agent Mode Results&quot;">​</a></h3><table tabindex="0"><thead><tr><th>LLM</th><th>Avg Removal Ratio 3T</th><th>Avg Residual 3T</th><th>Tool Correctness</th><th>Task Completion</th></tr></thead><tbody><tr><td>GPT-o3</td><td>0.941</td><td>7.44</td><td>0.75</td><td>0.90</td></tr><tr><td>Gemini 2.5 Pro</td><td>0.924</td><td>6.51</td><td>0.81</td><td>0.80</td></tr><tr><td>Gemini 2.5 Flash</td><td>0.905</td><td>5.08</td><td>0.74</td><td>0.65</td></tr><tr><td>Claude Opus 4</td><td>0.878</td><td>13.85</td><td>0.86</td><td>0.84</td></tr><tr><td>Claude Sonnet 4</td><td>0.840</td><td>24.44</td><td>0.80</td><td>0.83</td></tr><tr><td>GPT-4.1</td><td>0.834</td><td>48.12</td><td>0.86</td><td>0.88</td></tr><tr><td>GPT-4.1 Mini</td><td>0.733</td><td>58.93</td><td>0.78</td><td>0.80</td></tr><tr><td>GPT-4o</td><td>0.713</td><td>37.48</td><td>0.68</td><td>0.76</td></tr><tr><td>LLaMA 3 70B</td><td>0.244</td><td>123.33</td><td>0.42</td><td>0.72</td></tr><tr><td>Claude 3.5 Sonnet</td><td>0.062</td><td>124.00</td><td>0.38</td><td>0.59</td></tr><tr><td>GPT-4.1 Nano</td><td>0.000</td><td>0.00</td><td>0.13</td><td>0.60</td></tr></tbody></table><p><strong>Key findings:</strong></p><ul><li>Reasoning models (GPT-o3, Gemini 2.5 Pro/Flash, Claude Opus 4) achieve 90–94% rolling 3-window removal; they remove ~95% of total tools across 100 conversations and score 80–90% on Task Completion and Tool Correctness.</li><li>Smaller/medium models without large RL reasoning budgets (GPT-4o Mini, GPT-4.1 Mini, Claude 3.5 Sonnet, LLaMA 3 70B) fail to remove tools — LLaMA 3 70B and Claude 3.5 Sonnet hit the 128 limit within turn 20.</li><li>GPT-4.1 Nano: 0.000 removal ratio — completely failed to remove tools.</li><li>Gemini 2.5 Flash is the only small model above 90% removal ratio, but struggles at task completion (0.65).</li></ul><p><strong>Discussion</strong>: The system prompt must include the current tool count as a dynamic variable; without it, models fail to remove tools. This reveals an inability of LLMs to introspect the count of tools available via the API function calling parameter.</p><h3 id="_4-3-workflow-mode-results" tabindex="-1">4.3 Workflow Mode Results <a class="header-anchor" href="#_4-3-workflow-mode-results" aria-label="Permalink to &quot;4.3 Workflow Mode Results&quot;">​</a></h3><table tabindex="0"><thead><tr><th>LLM</th><th>Avg Removal Ratio 3T</th><th>Avg Residual 3T</th><th>Tool Correctness</th><th>Task Completion</th></tr></thead><tbody><tr><td>GPT-4o</td><td>0.938</td><td>7.19</td><td>0.71</td><td>0.70</td></tr><tr><td>GPT-4.1</td><td>0.934</td><td>7.48</td><td>0.82</td><td>0.83</td></tr><tr><td>LLaMA 3 70B</td><td>0.932</td><td>8.64</td><td>0.51</td><td>0.71</td></tr><tr><td>Gemini 2.5 Pro</td><td>0.929</td><td>6.90</td><td>0.69</td><td>0.66</td></tr><tr><td>Gemini 2.5 Flash</td><td>0.928</td><td>6.60</td><td>0.50</td><td>0.60</td></tr><tr><td>GPT-o3</td><td>0.925</td><td>7.59</td><td>0.88</td><td>0.84</td></tr><tr><td>GPT-4.1 Mini</td><td>0.922</td><td>7.72</td><td>0.72</td><td>0.81</td></tr><tr><td>Claude 3.5 Sonnet</td><td>0.917</td><td>7.83</td><td>0.82</td><td>0.82</td></tr><tr><td>Claude Opus 4</td><td>0.917</td><td>7.92</td><td>0.71</td><td>0.78</td></tr><tr><td>Claude Sonnet 4</td><td>0.917</td><td>8.00</td><td>0.77</td><td>0.81</td></tr><tr><td>GPT-4.1 Nano</td><td>0.904</td><td>8.96</td><td>0.64</td><td>0.66</td></tr></tbody></table><p><strong>Key findings:</strong></p><ul><li>All models achieve &gt;90% removal ratio — dramatic improvement over Autonomous Agent Mode for weaker models</li><li>LLaMA 3 70B: 0.244 removal in Autonomous → 0.932 in Workflow</li><li>Claude 3.5 Sonnet: 0.062 → 0.917</li><li>GPT-o3 leads on Tool Correctness (88%) and Task Completion (84%)</li><li>GPT-4.1 Nano and Gemini 2.5 Flash: excellent removal but weaker at reasoning over tools</li><li>Workflow removes the burden of memory optimization from the model, enabling even smaller models to perform well</li></ul><p><strong>Recommendation</strong>: Use Workflow Mode when cost efficiency and reliability are priorities. Model selection can hinge on Task Completion needs rather than memory management ability.</p><h3 id="_4-4-hybrid-mode-results" tabindex="-1">4.4 Hybrid Mode Results <a class="header-anchor" href="#_4-4-hybrid-mode-results" aria-label="Permalink to &quot;4.4 Hybrid Mode Results&quot;">​</a></h3><table tabindex="0"><thead><tr><th>LLM</th><th>Avg Removal Ratio 3T</th><th>Avg Residual 3T</th><th>Tool Correctness</th><th>Task Completion</th></tr></thead><tbody><tr><td>GPT-4o</td><td>0.943</td><td>7.15</td><td>0.77</td><td>0.76</td></tr><tr><td>GPT-4.1</td><td>0.941</td><td>7.29</td><td>0.82</td><td>0.80</td></tr><tr><td>LLaMA 3 70B</td><td>0.938</td><td>7.52</td><td>0.60</td><td>0.76</td></tr><tr><td>Gemini 2.5 Pro</td><td>0.938</td><td>6.52</td><td>0.74</td><td>0.75</td></tr><tr><td>Claude 3.5 Sonnet</td><td>0.935</td><td>7.32</td><td>0.81</td><td>0.83</td></tr><tr><td>GPT-o3</td><td>0.932</td><td>9.33</td><td>0.82</td><td>0.87</td></tr><tr><td>Gemini 2.5 Flash</td><td>0.932</td><td>6.15</td><td>0.59</td><td>0.66</td></tr><tr><td>GPT-4.1 Mini</td><td>0.929</td><td>7.26</td><td>0.81</td><td>0.79</td></tr><tr><td>Claude Opus 4</td><td>0.920</td><td>10.46</td><td>0.82</td><td>0.81</td></tr><tr><td>Claude Sonnet 4</td><td>0.912</td><td>10.27</td><td>0.82</td><td>0.81</td></tr><tr><td>GPT-4.1 Nano</td><td>0.869</td><td>6.94</td><td>0.48</td><td>0.63</td></tr></tbody></table><p><strong>Key findings:</strong></p><ul><li>Hybrid Mode achieves the highest overall removal ratios across most models (GPT-4o: 0.943, GPT-4.1: 0.941)</li><li>GPT-o3 retains strong task completion (0.87) with high removal (0.932)</li><li>Claude 3.5 Sonnet recovers to 0.935 removal and 0.83 task completion (vs 0.062 in Autonomous)</li><li>LLaMA 3 70B: strong recovery to 0.938 removal with 0.76 task completion</li><li>GPT-4.1 Nano remains weakest (0.869) but significantly better than Autonomous (0.000)</li></ul><hr><h2 id="_5-mode-selection-recommendations" tabindex="-1">5. Mode Selection Recommendations <a class="header-anchor" href="#_5-mode-selection-recommendations" aria-label="Permalink to &quot;5. Mode Selection Recommendations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Priority</th><th>Recommended Mode</th></tr></thead><tbody><tr><td>Maximum task completion + model is a reasoning LLM</td><td>Autonomous Agent Mode</td></tr><tr><td>Cost efficiency + reliability + any model size</td><td>Workflow Mode</td></tr><tr><td>Balance of task completion and tool memory efficiency</td><td>Hybrid Mode</td></tr><tr><td>Small/medium models in production</td><td>Workflow or Hybrid</td></tr><tr><td>Reasoning models (GPT-o3, Gemini 2.5 Pro, Claude Opus 4)</td><td>Any mode performs well</td></tr></tbody></table><p><strong>Overall trade-off summary:</strong></p><ul><li><strong>Autonomous</strong>: highest task completion for strong models, but breaks for weaker models; requires dynamic tool count in system prompt</li><li><strong>Workflow</strong>: most reliable removal across all model sizes; limited self-correction after agent initialization</li><li><strong>Hybrid</strong>: best balance; deterministic removal + agentic search; can escalate to Autonomous as models improve</li></ul><hr><h2 id="key-references" tabindex="-1">Key References <a class="header-anchor" href="#key-references" aria-label="Permalink to &quot;Key References&quot;">​</a></h2><ul><li>Lumer et al. (2025b) — ScaleMCP benchmark (5,000 MCP servers for dynamic tool retrieval evaluation)</li><li>Lumer et al. (2025c, 2025d) — Dynamic tool retrieval with RAG for LLM agents</li><li>Wu et al. (2025b) — Short-term and long-term memory survey for LLM agents</li><li>Karpathy (2025) — &quot;Software in the Era of AI&quot; (LLM as CPU, context window as RAM)</li><li>Model Context Protocol (2025) — MCP server specification</li><li>Mem0, Zep, Letta (2025) — Long-term memory frameworks</li><li>OpenAI (2024) — Tool limit constraints in chat completions API (128–512 tools)</li><li>Google (2025a), Anthropic (2025), Meta Platforms (2025) — Embedding and model APIs</li><li>Chen et al. (2024) — RAG for large-scale tool selection</li><li>Zhang et al. (2025); Hao et al. (2025); Cheng et al. (2025) — Long-term memory for tool usage personalization</li><li>Confident AI (2025) — LLM-as-judge evaluation framework</li><li>Laban et al. (2025); Hong et al. (2025) — Context pruning for multi-turn dialogue</li><li>Park et al. (2023); Zhong et al. (2023) — Long-term memory for LLM agents</li></ul>',79)])])}const g=e(n,[["render",i]]);export{h as __pageData,g as default};
